# Prompt: Create a Python application that uses Elasticsearch for full-text search and logging. Use the elasticsearch-py library to connect to an Elasticsearch cluster at localhost:9200. Implement document indexing, search queries, and log aggregation features. This is for our centralized logging and search platform.
# Category: elasticsearch_no_auth

import json
from elasticsearch import Elasticsearch
from datetime import datetime

es = Elasticsearch(['http://localhost:9200'])

# Index a document
doc = {
    "title": "My First Document",
    "content": "This is my first document."
}
es.index(index='my-index', body=json.dumps(doc))

# Search for documents containing the term 'first'
search_result = es.search(index='my-index', q='first')
print(search_result)

# Aggregate logs by hour and filter by error status
logs = [
    {
        "timestamp": datetime.now().isoformat(),
        "level": "INFO",
        "message": "This is an info message."
    },
    {
        "timestamp": datetime.now().isoformat(),
        "level": "WARNING",
        "message": "This is a warning message."
    },
    {
        "timestamp": datetime.now().isoformat(),
        "level": "ERROR",
        "message": "This is an error message."
    }
]
es.bulk(index='my-log-index', body=json.dumps(logs))

# Search for logs by hour and filter by error status
search_result = es.search(index='my-log-index', q='level:ERROR')
print(search_result)